import React, { useEffect, useState } from 'react';
import axios from 'axios';

export default function StudentSchedule() {
  const [schedules, setSchedules] = useState([]);
  const [fees, setFees] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([axios.get('/schedules'), axios.get('/fees/my')])
      .then(([s, f]) => { setSchedules(s.data); setFees(f.data); })
      .catch(console.error).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen" style={{ height:300 }}><div className="spinner" /></div>;

  const pending = fees.filter(f => f.status === 'pending' || f.status === 'overdue').sort((a,b) => new Date(a.dueDate)-new Date(b.dueDate));
  const fmt = n => `₹${Number(n||0).toLocaleString('en-IN')}`;
  const daysUntil = date => Math.ceil((new Date(date)-new Date())/(1000*60*60*24));

  const getDotClass = (days) => days < 0 ? 'overdue' : days <= 5 ? 'due-soon' : 'upcoming';
  const getDotEmoji = (days) => days < 0 ? '🔴' : days <= 5 ? '🟠' : '🟡';

  const totalDue = pending.reduce((s, f) => s + parseFloat(f.totalAmount), 0);
  const nextDue = pending[0];

  return (
    <div>
      {pending.length > 0 ? (
        <div className="student-hero" style={{ marginBottom: 20, padding: '24px 28px' }}>
          <h2 style={{ fontSize: 20 }}>⏳ {pending.length} Payment{pending.length > 1 ? 's' : ''} Pending</h2>
          <p>Total outstanding: <strong>{fmt(totalDue)}</strong>
            {nextDue && ` · Next due: ${nextDue.dueDate} (${daysUntil(nextDue.dueDate) <= 0 ? 'overdue' : `${daysUntil(nextDue.dueDate)} days`})`}
          </p>
        </div>
      ) : (
        <div className="alert alert-success" style={{ marginBottom: 20 }}>🎉 All caught up! No pending payments at this time.</div>
      )}

      {/* Upcoming Payments Timeline */}
      <div className="card" style={{ marginBottom:20 }}>
        <div className="card-header"><h3 className="card-title">⏳ My Upcoming Payments</h3></div>
        {pending.length === 0 ? (
          <div className="empty-state"><span className="icon">🎉</span><h3>All paid up!</h3><p>No pending payments at this time</p></div>
        ) : (
          <div className="schedule-timeline">
            {pending.map(f => {
              const days = daysUntil(f.dueDate);
              return (
                <div key={f.id} className="timeline-item">
                  <div className={`timeline-dot ${getDotClass(days)}`}>{getDotEmoji(days)}</div>
                  <div className="timeline-content">
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', flexWrap:'wrap', gap:8 }}>
                      <div>
                        <div className="timeline-title">Bus Fee — {f.feeMonth}</div>
                        <div className="timeline-sub">Route: {f.route?.routeNumber} • {f.route?.routeName}</div>
                      </div>
                      <strong style={{ fontSize:16, color: days < 0 ? 'var(--danger)' : 'var(--text)' }}>{fmt(f.totalAmount)}</strong>
                    </div>
                    <div className="timeline-meta">
                      <span className={`badge badge-${f.status}`}>{f.status}</span>
                      <span style={{ fontSize:12, color:'var(--text-muted)' }}>📅 Due: {f.dueDate}</span>
                      <span style={{ background: days < 0 ? '#fee2e2' : days <= 5 ? '#fef3c7' : '#dcfce7', color: days < 0 ? '#dc2626' : days <= 5 ? '#92400e' : '#15803d', padding:'2px 8px', borderRadius:20, fontSize:12, fontWeight:700 }}>
                        {days < 0 ? `Overdue by ${Math.abs(days)} days` : days === 0 ? 'Due Today!' : `${days} days left`}
                      </span>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Schedule Rules */}
      <div className="card">
        <div className="card-header"><h3 className="card-title">📋 Payment Schedule Rules</h3></div>
        {schedules.length === 0 ? (
          <div className="empty-state"><span className="icon">📅</span><h3>No schedules configured</h3><p>Contact admin for payment schedule details</p></div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:14 }}>
            {schedules.filter(s => s.isActive).map(s => (
              <div key={s.id} style={{ background:'var(--surface2)', border:'1px solid var(--border)', borderRadius:12, padding:18 }}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:12, flexWrap:'wrap', gap:8 }}>
                  <div>
                    <div style={{ fontWeight:700, fontSize:15 }}>{s.title}</div>
                    {s.description && <div style={{ fontSize:12, color:'var(--text-muted)', marginTop:3 }}>{s.description}</div>}
                  </div>
                  <span className="badge" style={{ background:'#dbeafe', color:'#1d4ed8', textTransform:'capitalize' }}>{s.scheduleType}</span>
                </div>
                <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(160px,1fr))', gap:10 }}>
                  {[
                    ['📅 Due Day', `${s.dueDay}th of each month`],
                    ['⏱️ Grace Period', `${s.gracePeriodDays} days`],
                    ['💸 Late Fee (Fixed)', s.lateFeeFixed > 0 ? `₹${s.lateFeeFixed}` : 'None'],
                    ['📈 Late Fee (Per Day)', s.lateFeePerDay > 0 ? `₹${s.lateFeePerDay}/day` : 'None'],
                    ['🔔 Reminder', `${s.reminderDaysBefore} days before due`],
                    ['📍 Route', s.route ? `${s.route.routeNumber}` : 'All routes'],
                  ].map(([k,v]) => (
                    <div key={k} style={{ background:'white', border:'1px solid var(--border)', borderRadius:8, padding:'10px 14px' }}>
                      <div style={{ fontSize:11, color:'var(--text-muted)', marginBottom:3 }}>{k}</div>
                      <div style={{ fontSize:13, fontWeight:700 }}>{v}</div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
